#include <bits/stdc++.h>
using namespace std;
long long quick_mi(long long a,long long b,long long p){
    long long ans=1,num=a;
    while(b){
        if(b&1)ans*=num,ans%=p;
        b/=2;
        num*=num,num%=p;
    }
    return ans;
}
int main(){
    long long n,m,x,k;
    cin>>n>>m>>k>>x;
    //cout<<quick_mi(10,k,n);
    cout<<(((quick_mi(10,k,n)*m)%n)+x)%n;
    return 0;
}
